#include <bits/stdc++.h>
using namespace std;

int N;
bool col[15], diag1[30], diag2[30];
int cnt = 0;

void dfs(int row) {
    if (row == N) {
        cnt++;
        return;
    }
    for (int c = 0; c < N; c++) {
        if (col[c] || diag1[row + c] || diag2[row - c + N]) continue;
        col[c] = diag1[row + c] = diag2[row - c + N] = true;
        dfs(row + 1);
        col[c] = diag1[row + c] = diag2[row - c + N] = false;
    }
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> N;
    dfs(0);
    cout << cnt << '\n';
    return 0;
}
